// 1. Extraemos y unificamos todos los datos sin importar cómo los entregue n8n
let arr = [];

if (items.length === 1 && Array.isArray(items[0].json)) {
  // Caso A: n8n metió todo el array dentro del primer item
  arr = items[0].json;
} else if (items.length === 1 && items[0].json.body && Array.isArray(items[0].json.body)) {
  // Caso B: Viene envuelto en una propiedad 'body'
  arr = items[0].json.body;
} else {
  // Caso C (El tuyo): n8n dividió los resultados en múltiples items
  arr = items.map(item => item.json);
}

// 2. Filtramos para asegurarnos de que tengan un ID válido
const validServices = arr.filter(s => s && s.id);

if (validServices.length === 0) {
  return [{ json: { result: 'Este negocio no tiene servicios configurados aún.' } }];
}

// 3. Armamos la lista de texto
const lines = validServices.map((s, i) => {
  let line = (i + 1) + '. ' + s.name + ' (ID:' + s.id + ') - ' + s.duration_minutes + ' min';
  if (s.price) line += ' - $' + Number(s.price).toLocaleString('es-CL');
  if (s.description) line += ' — ' + s.description;
  return line;
});

// 4. Retornamos todo empacado en un solo item para que el Agente lo lea
return [{ json: { result: 'Servicios disponibles:\n' + lines.join('\n') } }];

// 1. Recolectar TODOS los items que envía n8n, no solo el primero
let arr = [];
if (items.length === 1 && Array.isArray(items[0].json)) {
  arr = items[0].json;
} else {
  arr = items.map(item => item.json);
}

// 2. Extraer la información de los barberos
const staffList = arr.map(item => {
  if (item.staff_members) return item.staff_members;
  return item;
}).filter(s => s && s.id);

// 3. Validar si hay resultados
if (!staffList.length) {
  return [{ json: { result: 'No hay profesionales disponibles para este servicio.' } }];
}

// 4. Formatear la lista para el bot
const lines = staffList.map((s, i) => {
  let line = (i + 1) + '. ' + s.name + ' (ID:' + s.id + ')';
  if (s.role) line += ' - ' + s.role;
  return line;
});

// 5. Entregar la respuesta final
return [{ json: { result: 'Profesionales disponibles:\n' + lines.join('\n') } }];

const data = items[0].json;
const slots = Array.isArray(data) ? data : [data];

if (!slots.length || (slots.length === 1 && !slots[0].slot_start)) {
  return [{ json: { result: 'No hay horarios disponibles para esa fecha. Intenta con otro dia.' } }];
}

const lines = slots.map(s => {
  // Extraer hora local directamente del ISO string (ej: "2026-06-21T18:00:00-04:00" → "18:00")
  const localTime = s.slot_start.substring(11, 16);
  return localTime + ' (SLOT:' + s.slot_start + ')';
});

return [{ json: { result: 'Horarios disponibles:\n' + lines.join(' | ') } }];

const data = items[0].json;

if (data.message && data.message.includes('SLOT_TAKEN')) {
  return [{ json: { result: 'Ese horario ya fue reservado por otra persona. Por favor elige otro horario.' } }];
}

if (data.code || data.hint) {
  return [{ json: { result: 'Error al crear la cita: ' + (data.message || 'Error desconocido') } }];
}

const start = new Date(data.starts_at);
const dateStr = start.toLocaleDateString('es-CL', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'America/Santiago' });
const timeStr = start.toLocaleTimeString('es-CL', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Santiago' });

return [{ json: { result: `Cita confirmada para ${data.client_name}:\nFecha: ${dateStr}\nHora: ${timeStr}\nTe enviaremos un recordatorio antes de tu cita. Si necesitas cancelar, solo escríbeme.`, appointment: data } }];

const data = items[0].json;

if (data.message && data.message.includes('NOT_FOUND')) {
  return [{ json: { result: 'No se encontró esa cita o ya fue cancelada anteriormente.' } }];
}

if (data.code || data.hint) {
  return [{ json: { result: 'Error al cancelar: ' + (data.message || 'Error desconocido') } }];
}

return [{ json: { result: 'Tu cita ha sido cancelada exitosamente.' } }];

const data = items[0].json;
const arr = Array.isArray(data) ? data : [data];

if (!arr.length || (arr.length === 1 && !arr[0].id)) {
  return [{ json: { result: 'No tienes citas próximas agendadas.' } }];
}

const lines = arr.map((a, i) => {
  const start = new Date(a.starts_at);
  const dateStr = start.toLocaleDateString('es-CL', { weekday: 'short', day: 'numeric', month: 'short', timeZone: 'America/Santiago' });
  const timeStr = start.toLocaleTimeString('es-CL', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Santiago' });
  const staffName = a.staff_members ? a.staff_members.name : '—';
  const svcName = a.services ? a.services.name : '—';
  return `${i + 1}. ${svcName} con ${staffName} - ${dateStr} ${timeStr} (ID: ${a.id.slice(0, 8)})`;
});

return [{ json: { result: 'Tus próximas citas:\n' + lines.join('\n'), bookings: arr } }];

// === ROUTER REFACTORIZADO Y ANTIBALAS ===
const input = items[0].json;

if (!input.user_id || input.user_id.trim() === '') {
  items[0].json = { error: true, message: 'Error interno: user_id no proporcionado.' };
  return items;
}

const plan = (input.plan || '').toLowerCase();
if (!plan.includes('full') && !plan.includes('complet')) {
  items[0].json = { error: true, message: 'El agendamiento no esta disponible en tu plan actual. Actualiza al plan Full.' };
  return items;
}

let instr = {};
let raw = (input.instruccion || input.instruction || '').trim();

// 🚨 LIMPIEZA CRÍTICA MÁXIMA (Evitamos RegExp con /.../ para que n8n no rompa el código)
if (raw) {
  // Usamos strings simples para que el copiado y pegado sea seguro
  raw = raw.replaceAll('```json', '').replaceAll('```', '');

  // Quita signos = al principio y comillas sueltas (mantenemos RegExp seguras en una sola línea)
  raw = raw.replace(/^=+/, '').replace(/^"|"$/g, '').trim();
}

try {
  if (raw) {
    instr = JSON.parse(raw);
  }
} catch (e) {
  // Si aun así falla el JSON completo, intentamos rescatar la acción si vino como texto plano
  let fallbackAction = raw.toLowerCase().replace(/[^a-z_]/g, ''); 
  instr = { action: fallbackAction };
}

const validActions = ['list_services', 'list_staff', 'get_slots', 'create_booking', 'cancel_booking', 'my_bookings'];
const action = (instr.action || '').trim().toLowerCase();

if (!validActions.includes(action)) {
  items[0].json = { error: true, message: 'Accion no valida: ' + action };
  return items;
}

// Extraer y limpiar campos del JSON
const sid = (instr.service_id || '').trim();
const stid = (instr.staff_id || '').trim();
const dt = (instr.date || '').trim();
const ss = (instr.slot_start || '').trim();
const aid = (instr.appointment_id || '').trim();

// Validar campos requeridos por accion
if (action === 'get_slots' && (!sid || !stid || !dt)) {
  items[0].json = { error: true, message: 'Para ver horarios necesito el servicio, profesional y fecha válida (YYYY-MM-DD).' };
  return items;
}
if (action === 'create_booking' && (!sid || !stid || !ss)) {
  items[0].json = { error: true, message: 'Para crear la cita necesito el servicio, profesional y horario.' };
  return items;
}
if (action === 'cancel_booking' && !aid) {
  items[0].json = { error: true, message: 'Para cancelar necesito el ID de la cita.' };
  return items;
}

items[0].json = {
  error: false,
  action: action,
  user_id: input.user_id.trim(),
  service_id: sid,
  staff_id: stid,
  date: dt,
  slot_start: ss,
  client_name: (instr.client_name || '').trim(),
  client_phone: (input.client_phone || '').trim(),
  appointment_id: aid
};

return items;

